public int getIntFromFormat(boolean advance) {
    int i = formatOff;
    int value = 0;
    boolean found = false;

    String fmt = (format != null) ? format : "";
    while (i < fmt.length()) {
        char c = fmt.charAt(i);
        if (Character.isDigit(c)) {
            found = true;
            value = value * 10 + (c - '0');
            i++;
        } else {
            break;
        }
    }

    if (!found) {
        // No explicit length or repeat count found
        return 1;
    }

    if (advance) {
        formatOff = i;
    }

    return value;
}
